import React, { useState, useEffect } from 'react';
import api from '../services/api';

const CrearOferta = () => {
  const [formData, setFormData] = useState({
    programa_formacion: '',
    modalidad: '',
    tipo_programa: '',
    tipo_oferta: '',
    cupo_maximo: '',
    ambiente: {
      nombre: ''
    },
    fechas: {
      inicio: '',
      fin: ''
    },
    ubicacion: {
      departamento: 'Cauca',
      municipio: '',
      direccion: ''
    },
    empresa_solicitante: '', // <-- CAMBIADO: ahora es un ID
    subsector_economico: {
      nombre: ''
    },
    programa_especial: '',
    convenio: {
      nombre: ''
    },
    horario: {
      hora_inicio: '08:00',
      hora_fin: '12:00',
      dias: []
    },
    firma_digital_pdf: null,
    carta_pdf: null
  });

  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');
  const [mostrarFormularioEmpresa, setMostrarFormularioEmpresa] = useState(false);

  // Estados para las opciones de los selects
  const [programas, setProgramas] = useState([]);
  const [modalidades, setModalidades] = useState([]);
  const [tiposPrograma, setTiposPrograma] = useState([]);
  const [tiposOferta, setTiposOferta] = useState([]);
  const [municipios, setMunicipios] = useState([]);
  const [programasEspeciales, setProgramasEspeciales] = useState([]);
  const [empresas, setEmpresas] = useState([]); // <-- NUEVO: lista de empresas

  // Estado para crear una nueva empresa
  const [nuevaEmpresa, setNuevaEmpresa] = useState({
    nombre: '',
    nit: '',
    fecha_creacion: '',
    tipo_empresa: 'Privada',
    direccion: '',
    representante_legal: {
      nombre_completo: '',
      documento_identidad: '',
      telefono: '',
      correo: ''
    },
    contacto: {
      nombre_completo: '',
      cargo: '',
      telefono: '',
      correo: ''
    },
    numero_empleados: ''
  });

  // Cargar datos de MongoDB al montar el componente
  useEffect(() => {
    cargarDatosIniciales();
  }, []);

  const cargarDatosIniciales = async () => {
    try {
      const [
        programasRes,
        modalidadesRes,
        tiposProgramaRes,
        tiposOfertaRes,
        municipiosRes,
        programasEspecialesRes,
        empresasRes // <-- NUEVO
      ] = await Promise.all([
        api.get('/programas-formacion'),
        api.get('/modalidades'),
        api.get('/tipos-programa'),
        api.get('/tipos-oferta'),
        api.get('/municipios'),
        api.get('/programas-especiales'),
        api.get('/empresas') // <-- NUEVO
      ]);

      setProgramas(programasRes.data.data || []);
      setModalidades(modalidadesRes.data.data || []);
      setTiposPrograma(tiposProgramaRes.data.data || []);
      setTiposOferta(tiposOfertaRes.data.data || []);
      setMunicipios(municipiosRes.data.data || []);
      setProgramasEspeciales(programasEspecialesRes.data.data || []);
      setEmpresas(empresasRes.data.data || []); // <-- NUEVO
    } catch (error) {
      console.error('Error cargando datos:', error);
    }
  };

  // Funciones para manejar la nueva empresa
  const handleNuevaEmpresaChange = (e) => {
    const { name, value } = e.target;
    
    if (name.includes('.')) {
      const [parent, child] = name.split('.');
      setNuevaEmpresa({
        ...nuevaEmpresa,
        [parent]: {
          ...nuevaEmpresa[parent],
          [child]: value
        }
      });
    } else {
      setNuevaEmpresa({
        ...nuevaEmpresa,
        [name]: value
      });
    }
  };

  // ===== FUNCIÓN PARA MANEJAR ARCHIVOS PDF =====
const handleFileChange = (e) => {
  const { name, files } = e.target;
  if (files && files[0]) {
    // Validar que sea PDF
    if (files[0].type !== 'application/pdf') {
      setError('Solo se permiten archivos PDF');
      return;
    }
    
    // Validar tamaño (máximo 5MB)
    if (files[0].size > 5 * 1024 * 1024) {
      setError('El archivo no puede superar los 5MB');
      return;
    }

    setFormData({
      ...formData,
      [name]: files[0]
    });
  }
};



  const crearNuevaEmpresa = async () => {
    try {
      setLoading(true);
      
      // Validaciones básicas
      if (!nuevaEmpresa.nombre) throw new Error('El nombre de la empresa es obligatorio');
      if (!nuevaEmpresa.nit) throw new Error('El NIT es obligatorio');
      if (!nuevaEmpresa.fecha_creacion) throw new Error('La fecha de creación es obligatoria');
      if (!nuevaEmpresa.direccion) throw new Error('La dirección es obligatoria');
      if (!nuevaEmpresa.representante_legal.nombre_completo) throw new Error('El nombre del representante legal es obligatorio');
      if (!nuevaEmpresa.contacto.nombre_completo) throw new Error('El nombre del contacto es obligatorio');
      if (!nuevaEmpresa.contacto.telefono) throw new Error('El teléfono del contacto es obligatorio');
      if (!nuevaEmpresa.contacto.correo) throw new Error('El correo del contacto es obligatorio');
      if (!nuevaEmpresa.numero_empleados) throw new Error('El número de empleados es obligatorio');

      const response = await api.post('/empresas', nuevaEmpresa);
      
      // Agregar la nueva empresa a la lista
      setEmpresas([...empresas, response.data.data]);
      
      // Seleccionar la nueva empresa
      setFormData({
        ...formData,
        empresa_solicitante: response.data.data._id
      });
      
      // Cerrar el formulario de nueva empresa
      setMostrarFormularioEmpresa(false);
      
      // Limpiar el formulario de nueva empresa
      setNuevaEmpresa({
        nombre: '',
        nit: '',
        fecha_creacion: '',
        tipo_empresa: 'Privada',
        direccion: '',
        representante_legal: {
          nombre_completo: '',
          documento_identidad: '',
          telefono: '',
          correo: ''
        },
        contacto: {
          nombre_completo: '',
          cargo: '',
          telefono: '',
          correo: ''
        },
        numero_empleados: ''
      });

    } catch (error) {
      console.error('Error creando empresa:', error);
      if (error.response?.data?.message) {
        setError(error.response.data.message);
      } else {
        setError(error.message);
      }
    } finally {
      setLoading(false);
    }
  };

  const handleChange = (e) => {
    const { name, value } = e.target;
    
    if (name.includes('.')) {
      const [parent, child] = name.split('.');
      setFormData({
        ...formData,
        [parent]: {
          ...formData[parent],
          [child]: value
        }
      });
    } else {
      setFormData({
        ...formData,
        [name]: value
      });
    }
  };

  const handleDiaChange = (e) => {
    const { value, checked } = e.target;
    if (checked) {
      setFormData({
        ...formData,
        horario: {
          ...formData.horario,
          dias: [...formData.horario.dias, value]
        }
      });
    } else {
      setFormData({
        ...formData,
        horario: {
          ...formData.horario,
          dias: formData.horario.dias.filter(dia => dia !== value)
        }
      });
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');
    setSuccess('');

    try {
      // Validaciones
      if (!formData.programa_formacion) throw new Error('Seleccione un programa de formación');
      if (!formData.modalidad) throw new Error('Seleccione una modalidad');
      if (!formData.tipo_programa) throw new Error('Seleccione un tipo de programa');
      if (!formData.tipo_oferta) throw new Error('Seleccione un tipo de oferta');
      if (!formData.cupo_maximo) throw new Error('Ingrese el cupo máximo');
      if (!formData.ambiente.nombre) throw new Error('El nombre del modelo de ambiente es obligatorio');
      if (!formData.fechas.inicio || !formData.fechas.fin) throw new Error('Ingrese las fechas');
      if (!formData.ubicacion.municipio) throw new Error('Seleccione un municipio');
      if (!formData.empresa_solicitante) throw new Error('Seleccione una empresa solicitante'); // <-- CAMBIADO
      if (!formData.subsector_economico.nombre) throw new Error('Ingrese el subsector económico');
      if (!formData.convenio.nombre) throw new Error('El nombre del convenio es obligatorio');
      if (formData.horario.dias.length === 0) throw new Error('Seleccione al menos un día');

      const formDataToSend = new FormData();

      formDataToSend.append('programa_formacion', formData.programa_formacion);
      formDataToSend.append('modalidad', formData.modalidad);
      formDataToSend.append('tipo_programa', formData.tipo_programa);
      formDataToSend.append('tipo_oferta', formData.tipo_oferta);
      formDataToSend.append('cupo_maximo', formData.cupo_maximo);
      formDataToSend.append('ambiente[nombre]', formData.ambiente.nombre);
      formDataToSend.append('fechas[inicio]', formData.fechas.inicio);
      formDataToSend.append('fechas[fin]', formData.fechas.fin);
      formDataToSend.append('ubicacion[departamento]', formData.ubicacion.departamento);
      formDataToSend.append('ubicacion[municipio]', formData.ubicacion.municipio);
      formDataToSend.append('ubicacion[direccion]', formData.ubicacion.direccion);
      formDataToSend.append('empresa_solicitante', formData.empresa_solicitante);
      formDataToSend.append('subsector_economico[nombre]', formData.subsector_economico.nombre);
      formDataToSend.append('programa_especial', formData.programa_especial || '');
      formDataToSend.append('convenio[nombre]', formData.convenio.nombre);
      formDataToSend.append('horario[hora_inicio]', formData.horario.hora_inicio);
      formDataToSend.append('horario[hora_fin]', formData.horario.hora_fin);
      formData.horario.dias.forEach((dia, index) => {
        formDataToSend.append(`horario[dias][${index}]`, dia);
      });
      
      // ===== ARCHIVOS PDF =====
      if (formData.firma_digital_pdf) {
        formDataToSend.append('firma_digital_pdf', formData.firma_digital_pdf);
      }
      if (formData.carta_pdf) {
        formDataToSend.append('carta_pdf', formData.carta_pdf);
      }

      console.log('Enviando datos con archivos...');
      
      const response = await api.post('/ofertas', formDataToSend, {
        headers: {
          'Content-Type': 'multipart/form-data'
        }
      });
      
      setSuccess('✅ Oferta creada exitosamente');
      console.log('Respuesta:', response.data);
      
      setTimeout(() => {
        window.location.reload();
      }, 2000);
      
    } catch (error) {
      console.error('Error:', error);
      if (error.response?.data?.errors) {
        setError(error.response.data.errors.join(', '));
      } else if (error.response?.data?.message) {
        setError(error.response.data.message);
      } else {
        setError(error.message);
      }
    } finally {
      setLoading(false);
    }
  };


  const diasSemana = ['Lunes', 'Martes', 'Miércoles', 'Jueves', 'Viernes', 'Sábado', 'Domingo'];

  return (
    <div style={styles.container}>
      <h2 style={styles.title}>➕ Crear Nueva Oferta</h2>
      
      {error && <div style={styles.errorAlert}>❌ {error}</div>}
      {success && <div style={styles.successAlert}>✅ {success}</div>}

      <form onSubmit={handleSubmit} style={styles.form}>
        
        {/* PROGRAMA DE FORMACIÓN */}
        <div style={styles.section}>
          <h3 style={styles.sectionTitle}>Programa de Formación</h3>
          
          <div style={styles.formGroup}>
            <label style={styles.label}>Programa:</label>
            <select 
              name="programa_formacion"
              value={formData.programa_formacion}
              onChange={handleChange}
              style={styles.select}
              required
            >
              <option value="">Seleccione...</option>
              {programas.map(prog => (
                <option key={prog._id} value={prog._id}>
                  {prog.nombre_programa} - {prog.codigo}
                </option>
              ))}
            </select>
          </div>

          <div style={styles.formGroup}>
            <label style={styles.label}>Modalidad:</label>
            <select 
              name="modalidad"
              value={formData.modalidad}
              onChange={handleChange}
              style={styles.select}
              required
            >
              <option value="">Seleccione...</option>
              {modalidades.map(mod => (
                <option key={mod._id} value={mod._id}>
                  {mod.nombre}
                </option>
              ))}
            </select>
          </div>

          <div style={styles.formGroup}>
            <label style={styles.label}>Tipo de Programa:</label>
            <select 
              name="tipo_programa"
              value={formData.tipo_programa}
              onChange={handleChange}
              style={styles.select}
              required
            >
              <option value="">Seleccione...</option>
              {tiposPrograma.map(tp => (
                <option key={tp._id} value={tp._id}>
                  {tp.nombre}
                </option>
              ))}
            </select>
          </div>

          <div style={styles.formGroup}>
            <label style={styles.label}>Tipo de Oferta:</label>
            <select 
              name="tipo_oferta"
              value={formData.tipo_oferta}
              onChange={handleChange}
              style={styles.select}
              required
            >
              <option value="">Seleccione...</option>
              {tiposOferta.map(to => (
                <option key={to._id} value={to._id}>
                  {to.nombre}
                </option>
              ))}
            </select>
          </div>
        </div>

        {/* CUPOS */}
        <div style={styles.section}>
          <h3 style={styles.sectionTitle}>Cupos</h3>
          <div style={styles.formGroup}>
            <label style={styles.label}>Cupo Máximo:</label>
            <input 
              type="number"
              name="cupo_maximo"
              value={formData.cupo_maximo}
              onChange={handleChange}
              style={styles.input}
              placeholder="30"
              min="1"
              required
            />
          </div>
        </div>

        {/* AMBIENTE */}
        <div style={styles.section}>
          <h3 style={styles.sectionTitle}>Modelo de Ambiente</h3>
          <div style={styles.formGroup}>
            <label style={styles.label}>Nombre del Ambiente:</label>
            <input 
              type="text"
              name="ambiente.nombre"
              value={formData.ambiente.nombre}
              onChange={handleChange}
              style={styles.input}
              placeholder="Ej: Aula 101"
              required
            />
          </div>
        </div>

        {/* FECHAS */}
        <div style={styles.section}>
          <h3 style={styles.sectionTitle}>Fechas</h3>
          <div style={styles.row}>
            <div style={styles.half}>
              <label style={styles.label}>Fecha Inicio:</label>
              <input 
                type="date"
                name="fechas.inicio"
                value={formData.fechas.inicio}
                onChange={handleChange}
                style={styles.input}
                required
              />
            </div>
            <div style={styles.half}>
              <label style={styles.label}>Fecha Fin:</label>
              <input 
                type="date"
                name="fechas.fin"
                value={formData.fechas.fin}
                onChange={handleChange}
                style={styles.input}
                required
              />
            </div>
          </div>
        </div>

        {/* UBICACIÓN */}
        <div style={styles.section}>
          <h3 style={styles.sectionTitle}>Ubicación</h3>
          
          <div style={styles.formGroup}>
            <label style={styles.label}>Departamento:</label>
            <input 
              type="text"
              name="ubicacion.departamento"
              value={formData.ubicacion.departamento}
              onChange={handleChange}
              style={styles.input}
              placeholder="Cauca"
              required
            />
          </div>

          <div style={styles.formGroup}>
            <label style={styles.label}>Municipio:</label>
            <select 
              name="ubicacion.municipio"
              value={formData.ubicacion.municipio}
              onChange={handleChange}
              style={styles.select}
              required
            >
              <option value="">Seleccione...</option>
              {municipios.map(mun => (
                <option key={mun._id} value={mun._id}>
                  {mun.nombre}
                </option>
              ))}
            </select>
          </div>

          {/* ===== NUEVO CAMPO DE DIRECCIÓN ===== */}
          <div style={styles.formGroup}>
            <label style={styles.label}>Dirección:</label>
            <input 
              type="text"
              name="ubicacion.direccion"
              value={formData.ubicacion.direccion}
              onChange={handleChange}
              style={styles.input}
              placeholder="Calle 123 #45-67, Barrio Centro"
              required
            />
          </div>
        </div>
        {/* EMPRESA SOLICITANTE - MODIFICADO */}
        <div style={styles.section}>
          <h3 style={styles.sectionTitle}>Empresa Solicitante</h3>
          
          {!mostrarFormularioEmpresa ? (
            <>
              <div style={styles.formGroup}>
                <label style={styles.label}>Seleccionar Empresa:</label>
                <select 
                  name="empresa_solicitante"
                  value={formData.empresa_solicitante}
                  onChange={handleChange}
                  style={styles.select}
                  required
                >
                  <option value="">Seleccione una empresa...</option>
                  {empresas.map(emp => (
                    <option key={emp._id} value={emp._id}>
                      {emp.nombre} - NIT: {emp.nit}
                    </option>
                  ))}
                </select>
              </div>
              <button 
                type="button"
                onClick={() => setMostrarFormularioEmpresa(true)}
                style={styles.secondaryButton}
              >
                ➕ Crear Nueva Empresa
              </button>
            </>
          ) : (
            <div style={styles.subSection}>
              <h4 style={styles.subSectionTitle}>Nueva Empresa</h4>
              
              <div style={styles.formGroup}>
                <label style={styles.label}>Nombre de la Empresa:</label>
                <input
                  type="text"
                  name="nombre"
                  value={nuevaEmpresa.nombre}
                  onChange={handleNuevaEmpresaChange}
                  style={styles.input}
                  placeholder="Nombre de la empresa"
                />
              </div>

              <div style={styles.row}>
                <div style={styles.half}>
                  <label style={styles.label}>NIT:</label>
                  <input
                    type="text"
                    name="nit"
                    value={nuevaEmpresa.nit}
                    onChange={handleNuevaEmpresaChange}
                    style={styles.input}
                    placeholder="123456789-0"
                  />
                </div>
                <div style={styles.half}>
                  <label style={styles.label}>Fecha Creación:</label>
                  <input
                    type="date"
                    name="fecha_creacion"
                    value={nuevaEmpresa.fecha_creacion}
                    onChange={handleNuevaEmpresaChange}
                    style={styles.input}
                  />
                </div>
              </div>

              <div style={styles.row}>
                <div style={styles.half}>
                  <label style={styles.label}>Tipo de Empresa:</label>
                  <select
                    name="tipo_empresa"
                    value={nuevaEmpresa.tipo_empresa}
                    onChange={handleNuevaEmpresaChange}
                    style={styles.select}
                  >
                    <option value="Privada">Privada</option>
                    <option value="Pública">Pública</option>
                    <option value="Mixta">Mixta</option>
                    <option value="ONG">ONG</option>
                    <option value="Fundación">Fundación</option>
                    <option value="Cooperativa">Cooperativa</option>
                    <option value="Otro">Otro</option>
                  </select>
                </div>
                <div style={styles.half}>
                  <label style={styles.label}>Dirección:</label>
                  <input
                    type="text"
                    name="direccion"
                    value={nuevaEmpresa.direccion}
                    onChange={handleNuevaEmpresaChange}
                    style={styles.input}
                    placeholder="Dirección completa"
                  />
                </div>
              </div>

              <h4 style={styles.subSectionTitle}>Representante Legal</h4>
              <div style={styles.row}>
                <div style={styles.half}>
                  <label style={styles.label}>Nombre Completo:</label>
                  <input
                    type="text"
                    name="representante_legal.nombre_completo"
                    value={nuevaEmpresa.representante_legal.nombre_completo}
                    onChange={handleNuevaEmpresaChange}
                    style={styles.input}
                    placeholder="Nombre del representante"
                  />
                </div>
                <div style={styles.half}>
                  <label style={styles.label}>Documento:</label>
                  <input
                    type="text"
                    name="representante_legal.documento_identidad"
                    value={nuevaEmpresa.representante_legal.documento_identidad}
                    onChange={handleNuevaEmpresaChange}
                    style={styles.input}
                    placeholder="Documento de identidad"
                  />
                </div>
              </div>

              <div style={styles.row}>
                <div style={styles.half}>
                  <label style={styles.label}>Teléfono:</label>
                  <input
                    type="text"
                    name="representante_legal.telefono"
                    value={nuevaEmpresa.representante_legal.telefono}
                    onChange={handleNuevaEmpresaChange}
                    style={styles.input}
                    placeholder="Teléfono"
                  />
                </div>
                <div style={styles.half}>
                  <label style={styles.label}>Correo:</label>
                  <input
                    type="email"
                    name="representante_legal.correo"
                    value={nuevaEmpresa.representante_legal.correo}
                    onChange={handleNuevaEmpresaChange}
                    style={styles.input}
                    placeholder="correo@ejemplo.com"
                  />
                </div>
              </div>

              <h4 style={styles.subSectionTitle}>Contacto en la Empresa</h4>
              <div style={styles.row}>
                <div style={styles.half}>
                  <label style={styles.label}>Nombre Completo:</label>
                  <input
                    type="text"
                    name="contacto.nombre_completo"
                    value={nuevaEmpresa.contacto.nombre_completo}
                    onChange={handleNuevaEmpresaChange}
                    style={styles.input}
                    placeholder="Nombre del contacto"
                  />
                </div>
                <div style={styles.half}>
                  <label style={styles.label}>Cargo:</label>
                  <input
                    type="text"
                    name="contacto.cargo"
                    value={nuevaEmpresa.contacto.cargo}
                    onChange={handleNuevaEmpresaChange}
                    style={styles.input}
                    placeholder="Cargo del contacto"
                  />
                </div>
              </div>

              <div style={styles.row}>
                <div style={styles.half}>
                  <label style={styles.label}>Teléfono:</label>
                  <input
                    type="text"
                    name="contacto.telefono"
                    value={nuevaEmpresa.contacto.telefono}
                    onChange={handleNuevaEmpresaChange}
                    style={styles.input}
                    placeholder="Teléfono del contacto"
                  />
                </div>
                <div style={styles.half}>
                  <label style={styles.label}>Correo:</label>
                  <input
                    type="email"
                    name="contacto.correo"
                    value={nuevaEmpresa.contacto.correo}
                    onChange={handleNuevaEmpresaChange}
                    style={styles.input}
                    placeholder="correo@ejemplo.com"
                  />
                </div>
              </div>

              <div style={styles.formGroup}>
                <label style={styles.label}>Número de Empleados:</label>
                <input
                  type="number"
                  name="numero_empleados"
                  value={nuevaEmpresa.numero_empleados}
                  onChange={handleNuevaEmpresaChange}
                  style={styles.input}
                  placeholder="Ej: 50"
                  min="1"
                />
              </div>

              <div style={styles.buttonGroup}>
                <button 
                  type="button"
                  onClick={crearNuevaEmpresa}
                  style={styles.successButton}
                  disabled={loading}
                >
                  {loading ? 'Guardando...' : 'Guardar Empresa'}
                </button>
                <button 
                  type="button"
                  onClick={() => setMostrarFormularioEmpresa(false)}
                  style={styles.cancelButton}
                >
                  Cancelar
                </button>
              </div>
            </div>
          )}
        </div>

        {/* SUBSECTOR ECONÓMICO */}
        <div style={styles.section}>
          <h3 style={styles.sectionTitle}>Subsector Económico</h3>
          <div style={styles.formGroup}>
            <label style={styles.label}>Nombre:</label>
            <input 
              type="text"
              name="subsector_economico.nombre"
              value={formData.subsector_economico.nombre}
              onChange={handleChange}
              style={styles.input}
              placeholder="Ej: Tecnologías de la Información"
              required
            />
          </div>
        </div>

        {/* PROGRAMA ESPECIAL */}
        <div style={styles.section}>
          <h3 style={styles.sectionTitle}>Programa Especial</h3>
          <div style={styles.formGroup}>
            <select 
              name="programa_especial"
              value={formData.programa_especial}
              onChange={handleChange}
              style={styles.select}
            >
              <option value="">Ninguno</option>
              {programasEspeciales.map(pe => (
                <option key={pe._id} value={pe._id}>
                  {pe.nombre}
                </option>
              ))}
            </select>
          </div>
        </div>

        {/* CONVENIO */}
        <div style={styles.section}>
          <h3 style={styles.sectionTitle}>Convenio</h3>
          <div style={styles.formGroup}>
            <label style={styles.label}>Nombre del Convenio:</label>
            <input 
              type="text"
              name="convenio.nombre"
              value={formData.convenio.nombre}
              onChange={handleChange}
              style={styles.input}
              placeholder="Nombre del convenio"
              required
            />
          </div>
        </div>

        {/* HORARIO */}
        <div style={styles.section}>
          <h3 style={styles.sectionTitle}>Horario</h3>
          
          <div style={styles.row}>
            <div style={styles.half}>
              <label style={styles.label}>Hora Inicio:</label>
              <input 
                type="time"
                name="horario.hora_inicio"
                value={formData.horario.hora_inicio}
                onChange={handleChange}
                style={styles.input}
                required
              />
            </div>
            <div style={styles.half}>
              <label style={styles.label}>Hora Fin:</label>
              <input 
                type="time"
                name="horario.hora_fin"
                value={formData.horario.hora_fin}
                onChange={handleChange}
                style={styles.input}
                required
              />
            </div>
          </div>

          <div style={styles.formGroup}>
            <label style={styles.label}>Días:</label>
            <div style={styles.checkboxGroup}>
              {diasSemana.map(dia => (
                <label key={dia} style={styles.checkboxLabel}>
                  <input 
                    type="checkbox"
                    value={dia}
                    checked={formData.horario.dias.includes(dia)}
                    onChange={handleDiaChange}
                  /> {dia}
                </label>
              ))}
            </div>
          </div>
        </div>

        {/* ===== ARCHIVOS PDF ===== */}
        <div style={styles.section}>
          <h3 style={styles.sectionTitle}>Documentos Adjuntos</h3>
          
          {/* Firma Digital PDF */}
          <div style={styles.formGroup}>
            <label style={styles.label}>Firma Digital (PDF):</label>
            <div style={styles.fileInputGroup}>
              <input
                type="file"
                id="firma_digital_pdf"
                name="firma_digital_pdf"
                onChange={handleFileChange}
                style={styles.fileInput}
                accept=".pdf"
                required
              />
              {formData.firma_digital_pdf && (
                <div style={styles.fileInfo}>
                  <span style={styles.fileName}>{formData.firma_digital_pdf.name}</span>
                  <button
                    type="button"
                    onClick={() => {
                      document.getElementById('firma_digital_pdf').value = '';
                      setFormData({...formData, firma_digital_pdf: null});
                    }}
                    style={styles.removeFileButton}
                  >
                    ✕
                  </button>
                </div>
              )}
            </div>
            <small style={styles.fileHint}>Archivo PDF con la firma digital escaneada</small>
          </div>

          {/* Carta PDF */}
          <div style={styles.formGroup}>
            <label style={styles.label}>Carta (PDF):</label>
            <div style={styles.fileInputGroup}>
              <input
                type="file"
                id="carta_pdf"
                name="carta_pdf"
                onChange={handleFileChange}
                style={styles.fileInput}
                accept=".pdf"
                required
              />
              {formData.carta_pdf && (
                <div style={styles.fileInfo}>
                  <span style={styles.fileName}>{formData.carta_pdf.name}</span>
                  <button
                    type="button"
                    onClick={() => {
                      document.getElementById('carta_pdf').value = '';
                      setFormData({...formData, carta_pdf: null});
                    }}
                    style={styles.removeFileButton}
                  >
                    ✕
                  </button>
                </div>
              )}
            </div>
            <small style={styles.fileHint}>Documento PDF de la carta solicitante</small>
          </div>
        </div>


        <button 
          type="submit" 
          style={loading ? {...styles.submitButton, ...styles.buttonDisabled} : styles.submitButton}
          disabled={loading}
        >
          {loading ? 'Guardando...' : 'Guardar Oferta'}
        </button>
      </form>
    </div>
  );
};

const styles = {
  container: {
    maxWidth: '800px',
    margin: '0 auto',
    padding: '20px'
  },

  // Agrega estos estilos al objeto styles
  fileInputGroup: {
    display: 'flex',
    flexDirection: 'column',
    gap: '10px'
  },
  fileInfo: {
    display: 'flex',
    alignItems: 'center',
    gap: '10px',
    padding: '8px 12px',
    backgroundColor: '#ecf0f1',
    borderRadius: '4px'
  },
  fileName: {
    fontSize: '13px',
    color: '#2c3e50',
    flex: 1
  },
  removeFileButton: {
    backgroundColor: 'transparent',
    border: 'none',
    color: '#e74c3c',
    cursor: 'pointer',
    fontSize: '16px',
    fontWeight: 'bold',
    padding: '0 5px'
  },


  title: {
    color: '#2c3e50',
    borderBottom: '3px solid #3498db',
    paddingBottom: '10px',
    marginBottom: '30px',
    fontSize: '28px'
  },
  section: {
    backgroundColor: '#f8f9fa',
    padding: '20px',
    borderRadius: '8px',
    marginBottom: '25px',
    border: '1px solid #e0e0e0'
  },
  subSection: {
    backgroundColor: '#ffffff',
    padding: '15px',
    borderRadius: '6px',
    marginTop: '10px',
    border: '1px solid #3498db'
  },
  sectionTitle: {
    color: '#2c3e50',
    marginTop: 0,
    marginBottom: '20px',
    fontSize: '18px',
    borderBottom: '1px solid #3498db',
    paddingBottom: '5px'
  },
  subSectionTitle: {
    color: '#3498db',
    marginTop: 0,
    marginBottom: '15px',
    fontSize: '16px'
  },
  form: {
    display: 'flex',
    flexDirection: 'column',
    gap: '20px'
  },
  formGroup: {
    display: 'flex',
    flexDirection: 'column',
    gap: '5px',
    marginBottom: '15px'
  },
  row: {
    display: 'flex',
    gap: '20px',
    marginBottom: '15px'
  },
  half: {
    flex: 1,
    display: 'flex',
    flexDirection: 'column',
    gap: '5px'
  },
  label: {
    fontSize: '14px',
    fontWeight: 'bold',
    color: '#34495e'
  },
  input: {
    padding: '10px',
    border: '1px solid #ddd',
    borderRadius: '4px',
    fontSize: '14px',
    outline: 'none'
  },
  select: {
    padding: '10px',
    border: '1px solid #ddd',
    borderRadius: '4px',
    fontSize: '14px',
    backgroundColor: 'white',
    cursor: 'pointer'
  },
  checkboxGroup: {
    display: 'flex',
    flexWrap: 'wrap',
    gap: '15px',
    padding: '10px 0'
  },
  checkboxLabel: {
    display: 'flex',
    alignItems: 'center',
